prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?forwardTask ?emailTask ?forwardName ?emailName ?hasPathForwardToEmail ?hasPathEmailToForward WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0ba102e82f484407a4dbcb9bcafdd920" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?forwardTask a bboExt:ChoreographyTask .
  ?forwardTask tai:belongsTo ?choreo .
  ?forwardTask bbo:name ?forwardName .
  FILTER(CONTAINS(LCASE(STR(?forwardName)), LCASE("Forward Application")))

  ?emailTask a bboExt:ChoreographyTask .
  ?emailTask tai:belongsTo ?choreo .
  ?emailTask bbo:name ?emailName .
  FILTER(CONTAINS(LCASE(STR(?emailName)), LCASE("Email Results of Academic Review")))

  {
    SELECT DISTINCT ?forwardTask ?emailTask (true as ?hasPathForwardToEmail) WHERE {
      ?forwardTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?emailTask .
    }
  }
  OPTIONAL {
    FILTER EXISTS {
      ?emailTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?forwardTask .
    }
    BIND(true as ?hasPathEmailToForward)
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?forwardTask ?emailTask ?forwardName ?emailName ?forwardCanComeBefore ?emailCanComeBefore WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0ba102e82f484407a4dbcb9bcafdd920" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?forwardTask a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ; bbo:name ?forwardName .
  FILTER(CONTAINS(LCASE(STR(?forwardName)), LCASE("Forward Application")))

  ?emailTask a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ; bbo:name ?emailName .
  FILTER(CONTAINS(LCASE(STR(?emailName)), LCASE("Email Results of Academic Review")))

  {
    SELECT DISTINCT ?forwardTask ?emailTask WHERE {
      ?forwardTask ((bbo:has_sourceRef)/bbo:has_targetRef)+ ?emailTask .
    }
  }
  BIND(true as ?forwardCanComeBefore)

  OPTIONAL {
    FILTER EXISTS {
      ?emailTask ((bbo:has_sourceRef)/bbo:has_targetRef)+ ?forwardTask .
    }
    BIND(true as ?emailCanComeBefore)
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?forwardTaskName ?emailTaskName ?succFromForward ?succFromForwardName ?predOfEmail ?predOfEmailName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0ba102e82f484407a4dbcb9bcafdd920" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?forwardTask a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ; bbo:name ?forwardTaskName .
  FILTER(CONTAINS(LCASE(STR(?forwardTaskName)), LCASE("Forward Application")))

  ?emailTask a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ; bbo:name ?emailTaskName .
  FILTER(CONTAINS(LCASE(STR(?emailTaskName)), LCASE("Email Results of Academic Review")))

  OPTIONAL {
    ?fEdge a bbo:SequenceFlow ; bbo:has_sourceRef ?forwardTask ; bbo:has_targetRef ?succFromForward .
    OPTIONAL { ?succFromForward bbo:name ?succFromForwardName . }
  }
  OPTIONAL {
    ?eEdge a bbo:SequenceFlow ; bbo:has_targetRef ?emailTask ; bbo:has_sourceRef ?predOfEmail .
    OPTIONAL { ?predOfEmail bbo:name ?predOfEmailName . }
  }
}
LIMIT 25
